import {derived, writable, get} from "svelte/store";
import {i18n, initPagination, pageUpdate, showMessage, withLoading} from "../../utils.js";
import {appLang, appName, csrfToken, isSuperuser} from "../../constants.js";
import {categoryInfo} from "../../regions/similarity/similarityCategory.js";

export function createClusterStore(documentSetStore, clusterSelection) {
    const pageLength = 10;
    const currentPage = writable(1);

    const {visiblePairs, imageNodes} = documentSetStore;

    initPagination(currentPage, "p");

    function handlePageUpdate(pageNb) {
        pageUpdate(pageNb, currentPage, "p");
    }

    function findClusters(pairs) {
        if (pairs.length === 0) return [];
        const parent = new Map();

        const find = (img) => {
            if (!parent.has(img)) {
                parent.set(img, img);
                return img;
            }
            if (parent.get(img) !== img) {
                parent.set(img, find(parent.get(img)));
            }
            return parent.get(img);
        };

        const union = (a, b) => {
            const rootA = find(a);
            const rootB = find(b);
            if (rootA !== rootB) {
                parent.set(rootB, rootA);
            }
        };

        const imageIds = new Set();
        pairs.forEach(p => {
            union(p.id_1, p.id_2)
            imageIds.add(p.id_1);
            imageIds.add(p.id_2);
        });

        const clusterMap = new Map();
        imageIds.forEach(imgId => {
            const root = find(imgId);
            if (!clusterMap.has(root)) {
                clusterMap.set(root, []);
            }
            clusterMap.get(root).push(imgId);
        });

        return Array.from(clusterMap.values())
            .map(members => {
                const n = members.length;
                const maxEdges = (n * (n - 1)) / 2;
                const imageSet = new Set(members);
                let actualLinks = 0;
                let allCategory1 = true;
                for (const p of pairs) {
                    if (imageSet.has(p.id_1) && imageSet.has(p.id_2)) {
                        actualLinks++;
                        if (allCategory1 && p.category !== 1) allCategory1 = false;
                    }
                }

                return {
                    id: crypto.randomUUID(),
                    members,
                    size: n,
                    fullyConnected: actualLinks >= maxEdges && allCategory1
                };
            })
            .filter(c => c.size > 1)
            .sort((a, b) => b.size - a.size);
    }

    /**
     * Clusters { id, members: [imgId1, imgId2, ...], size, fullyConnected }
     */
    const imageClusters = derived(visiblePairs, ($pairs) => {
        if (!$pairs.length) return [];
        return findClusters($pairs);
    });

    // UI clusters, manipulable without needing to rerun findClusters
    const interfaceClusters = writable([]);
    imageClusters.subscribe($clusters => {
        interfaceClusters.set($clusters);
    });

    const paginatedClusters = derived([interfaceClusters, currentPage], ([$clusters, $currentPage]) => {
        const start = ($currentPage - 1) * pageLength;
        const end = start + pageLength;
        return $clusters.slice(start, end);
    });

    const pairData = (ref1, ref2) => {
        const img1 = get(imageNodes).get(ref1);
        const img2 = get(imageNodes).get(ref2);

        return {
            img_1: img1?.id || ref1,
            img_2: img2?.id || ref2,
        };
    };

    const removeImgsFromInterface = (imgRefSet, byOriginCluster) => {
        interfaceClusters.update($clusters =>
            $clusters
                .map(c => {
                    if (!byOriginCluster[c.id]) return c;
                    const remaining = c.members.filter(m => !imgRefSet.has(m));
                    return {...c, members: remaining, size: remaining.length};
                })
                .filter(c => c.size > 0)
        );
        return true;
    }

    const removeImgRefs = async (imgRefs) => {
        const imgRefArray = Array.isArray(imgRefs) ? imgRefs : Object.keys(imgRefs);
        const imgRefSet = new Set(imgRefArray);

        const byOriginCluster = {};
        get(interfaceClusters).forEach(cluster => {
            const selected = cluster.members.filter(m => imgRefSet.has(m));
            if (selected.length > 0) {
                byOriginCluster[cluster.id] = selected;
            }
        });

        const pairsToRemove = Object.entries(byOriginCluster).flatMap(([clusterId, selectedRefs]) => {
            const cluster = get(interfaceClusters).find(c => c.id === clusterId);
            if (!cluster) return [];

            const remaining = cluster.members.filter(m => !imgRefSet.has(m));
            return selectedRefs.flatMap(sel =>
                remaining.map(rem => pairData(sel, rem))
            );
        });

        if (pairsToRemove.length === 0) {
            removeImgsFromInterface(imgRefSet, byOriginCluster)
            return true;
        }

        try {
            const response = await withLoading(() => fetch(`${window.location.origin}/${appName}/uncategorize-batch`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "X-CSRFToken": csrfToken
                },
                body: JSON.stringify({pairs: pairsToRemove})
            }));

            if (!response.ok) {
                console.log(response)
                await showMessage(
                    appLang === "en" ? "Batch un-categorization failed" : "La dé-catégorisation par lot a échoué",
                    i18n("error"),
                );
                return false;
            }

            removeImgsFromInterface(imgRefSet, byOriginCluster);

            return true;
        } catch (error) {
            await showMessage(
                error,
                i18n("error"),
            );
            return false;
        }
    };

    const categorizePairs = async (imgRefs, category) => {
        const pairs = imgRefs.flatMap((ref1, i) =>
            imgRefs.slice(i + 1).map(ref2 => pairData(ref1, ref2))
        );

        try {
            const response = await withLoading(() => fetch(`${window.location.origin}/${appName}/categorize-batch`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "X-CSRFToken": csrfToken
                },
                body: JSON.stringify({ pairs, category })
            }));

            if (!response.ok) {
                console.log(response)
                await showMessage(
                    appLang === "en" ? "Batch categorization failed" : "La catégorisation par lot a échoué",
                    i18n("error"),
                );
                return false;
            }

            return true;
        } catch (error) {
            await showMessage(error, i18n("error"));
            console.error("Error:", error);
            return false;
        }
    };

    const categorizeSelection = async (category) => {
        const selected = selectedDocs();
        const imgRefs = Object.keys(selected);

        if (imgRefs.length < 2) {
            await showMessage(
                appLang === "en" ? "Select at least 2 images" : "Sélectionnez au moins 2 images",
                i18n("error"),
            );
            return false;
        }

        const confirmed = await showMessage(
            appLang === "en"
                ? `Categorize ${imgRefs.length} images as "${categoryInfo[category].title}"?`
                : `Catégoriser ${imgRefs.length} images en tant que « ${categoryInfo[category].title} » ?`,
            appLang === "en" ? "Confirm categorization" : "Confirmer la catégorisation",
            true
        );
        if (!confirmed) return false;

        const success = await createCluster(imgRefs, category);
        if (success) clusterSelection.empty();
        return success;
    };

    const validateCluster = async (cluster) => {
        if (!isSuperuser){
            await showMessage(
                appLang === "en" ? "You do not have permission to validate clusters" : "Vous n'avez pas la permission, de valider les clusters.",
                appLang === "en" ? "Permission Denied" : "Permission refusée"
            );
            return false;
        }

        const success = await categorizePairs(cluster.members, 1);

        if (success) {
            interfaceClusters.update($clusters =>
                $clusters.map(c =>
                    c.id === cluster.id ? {...c, fullyConnected: true} : c
                )
            );
        }

        return success;
    };

    const createCluster = async (imgRefs, category = 1) => {
        if (imgRefs.length < 2) return false;

        const success = await categorizePairs(imgRefs, category);
        if (!success) return false;

        const imgRefSet = new Set(imgRefs);
        const byOriginCluster = {};
        get(interfaceClusters).forEach(cluster => {
            if (cluster.members.some(m => imgRefSet.has(m))) {
                byOriginCluster[cluster.id] = true;
            }
        });
        removeImgsFromInterface(imgRefSet, byOriginCluster);

        interfaceClusters.update($clusters => [
            {
                id: crypto.randomUUID(),
                members: imgRefs,
                size: imgRefs.length,
                fullyConnected: category === 1
            },
            ...$clusters
        ].sort((a, b) => b.size - a.size));

        return true;
    };

    const selectedDocs = () => get(clusterSelection).selected.regions || {};

    const newCluster = async () => {
        const confirmed = await showMessage(
            appLang === "en" ? "Do you want to create a cluster out of these images?" : "Voulez-vous créer un cluster à partir de ces images ?",
            appLang === "en" ? "Confirm creation" : "Confirmer la création",
            true
        );
        if (!confirmed) {
            return;
        }

        const selected = selectedDocs();
        const imgRefs = Object.keys(selected);

        if (imgRefs.length < 2) {
            await showMessage(
                appLang === "en" ? "Cluster creation requires at least 2 images" : "La création d'un nouveau cluster nécessite a minima 2 images",
                appLang === "en" ? "Impossible creation" : "Création impossible",
            );
            return false;
        }

        const removed = await removeImgRefs(imgRefs);
        if (!removed) return false;

        const created = await createCluster(imgRefs);
        if (!created) return false;

        clusterSelection.empty();
        return true;
    };

    const removeFromClusters = async () => {
        const confirmed = await showMessage(
            appLang === "en" ? "Do you want to remove these images from their clusters?" : "Voulez-vous supprimer ces images de leurs clusters ?",
            appLang === "en" ? "Confirm deletion" : "Confirmer la suppression",
            true
        );
        if (!confirmed) {
            return;
        }

        const selected = selectedDocs();
        const removed = await removeImgRefs(Object.keys(selected));
        if (!removed) return false;

        clusterSelection.empty();
        return true;
    };

    return {
        imageClusters,
        interfaceClusters,
        clusterNb: derived(interfaceClusters, $clusters => $clusters.length),

        validateCluster,
        removeFromClusters,
        categorizeSelection,
        newCluster,

        paginatedClusters,
        handlePageUpdate,
        pageLength,
        currentPage
    };
}
